        switch result {
        case .completed:
            paymentStatus = "Payment completed"
            paymentResultText = "Investor demo purchase successful"
        case .canceled:
            paymentStatus = "Payment canceled"
            paymentResultText = "User canceled the demo payment"
        case .failed(let error):
            paymentStatus = "Payment failed"
            paymentResultText = error.localizedDescription
        }
