struct PaymentSheetPresenter: UIViewControllerRepresentable {
    let paymentSheet: PaymentSheet?
    let onCompletion: (PaymentSheetResult) -> Void

    func makeUIViewController(context: Context) -> PaymentHostViewController {
        let controller = PaymentHostViewController()
        controller.paymentSheet = paymentSheet
        controller.onCompletion = onCompletion
        return controller
    }

    func updateUIViewController(_ uiViewController: PaymentHostViewController, context: Context) {}
}

final class PaymentHostViewController: UIViewController {
    var paymentSheet: PaymentSheet?
    var onCompletion: ((PaymentSheetResult) -> Void)?

    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)
        guard let paymentSheet = paymentSheet else {
            dismiss(animated: true)
            return
        }

        paymentSheet.present(from: self) { [weak self] result in
            self?.onCompletion?(result)
            self?.dismiss(animated: true)
        }
    }
}